app.get('/me', (req, res) => {
  if (!req.session.user) {
    res.status(401).type('html').send(`<p>Not authenticated. <a href="/login">Login</a></p>`);
    return;
  }
  res.json({
    user: req.session.user,
    tokens: req.session.tokens,
  });
});

app.get('/logout', (req, res) => {
  req.session.destroy(() => {
    res.clearCookie('sid');
    res.redirect('/');
  });
});

app.use((err, req, res, next) => {
  const status = err.status || 500;
  res.status(status).json({
    error: 'server_error',
    message: err.message,
    details: err.details || undefined,
  });
});

function escapeHtml(s) {
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

